package com.pqc.core.security;
import com.pqc.core.entity.*; import com.pqc.core.repository.UserRepository; import org.junit.jupiter.api.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.boot.webmvc.test.autoconfigure.AutoConfigureMockMvc; import org.springframework.jdbc.core.JdbcTemplate; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.test.context.ActiveProfiles; import org.springframework.test.web.servlet.MockMvc; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;
@SpringBootTest @AutoConfigureMockMvc @ActiveProfiles("test") class MarketingAdminSecurityTest {@Autowired MockMvc mvc;@Autowired UserRepository users;@Autowired PasswordEncoder encoder;@Autowired JwtService jwt;@Autowired JdbcTemplate jdbc;
@BeforeEach void clean(){jdbc.execute("SET REFERENTIAL_INTEGRITY FALSE");for(String t:new String[]{"marketing_notifications","marketing_banners","marketing_campaigns","offers","plumber_kyc","support_messages","support_tickets","refund_requests","settlements","outbox_events","inventory_reservations","product_order_items","product_orders","service_orders","stocks","stores","user_addresses","wallet_transactions","wallets","refresh_tokens","notifications","users"})try{jdbc.execute("TRUNCATE TABLE "+t+" RESTART IDENTITY");}catch(Exception ignored){}jdbc.execute("SET REFERENTIAL_INTEGRITY TRUE");}
@Test void accessBoundary()throws Exception{for(Role r:new Role[]{Role.SUPER_ADMIN,Role.ADMIN,Role.MARKETING_ADMIN})mvc.perform(get("/api/v1/admin/marketing/dashboard").header("Authorization",bearer(save(r)))).andExpect(status().isOk());for(Role r:new Role[]{Role.OPERATIONS_ADMIN,Role.FINANCE_ADMIN,Role.SUPPORT_ADMIN,Role.PLUMBER_MANAGER,Role.CUSTOMER,Role.PLUMBER,Role.STORE_MANAGER,Role.DELIVERY_PARTNER})mvc.perform(get("/api/v1/admin/marketing/dashboard").header("Authorization",bearer(save(r)))).andExpect(status().isForbidden());}private User save(Role r){return users.save(User.builder().email(r.name()+"@m.test").password(encoder.encode("x")).fullName(r.name()).phone("9"+r.ordinal()).role(r).status(UserStatus.ACTIVE).build());}private String bearer(User u){return "Bearer "+jwt.generateToken(u.getEmail(),u.getRole().name());}}
